    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Llevo 5 años en C++ y empecé Rust hace un año. La curva de aprendizaje es real pero el borrow checker te enseña a pensar en ownership de una manera que hace mejor tu C++ también.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Exactamente eso. Entender por qué Rust prohíbe ciertas cosas ilumina por qué tantos bugs en C++ son posibles en primer lugar.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El problema es que en C++ tienes décadas de bibliotecas maduras. Rust aún no tiene equivalente para muchos dominios específicos como simulación física o gráficos de bajo nivel.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Eso está cambiando rápido. El ecosistema de Rust en WebGPU y gráficos está creciendo exponencialmente. wgpu ya es bastante capaz.</p>', alex) RETURNING id INTO r4;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r4, '<p>Para sistemas embebidos Rust también está ganando terreno serio. Los microcontroladores ARM ahora tienen soporte decente y las garantías de seguridad son muy valiosas en ese contexto.</p>', hannah) RETURNING id INTO r5;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r5, '<p>El kernel de Linux aceptando código Rust fue la señal definitiva. Si Linus Torvalds lo acepta, el debate se acabó en mi cabeza.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>En mi empresa migramos un servicio crítico de C++ a Rust y los crashes por segfaults desaparecieron completamente. El tiempo de desarrollo aumentó inicialmente pero la estabilidad en producción lo justificó.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>¿Cuánto tiempo tardó la migración? Ese es el argumento que más escucho en contra: el costo de reescribir código que funciona.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Seis meses para un servicio de 50k líneas. Doloroso pero los crashes en producción que teníamos cada semana valían más en tiempo de ingeniería.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Ese ROI tiene sentido para servicios críticos. Para código interno que solo corre en servidores controlados, C++ sigue siendo perfectamente válido.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El async en Rust con Tokio es más complicado que en Go o incluso C++ moderno con coroutines. Esa es una fricción real para equipos nuevos en el lenguaje.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Rust tiene el mejor tooling de cualquier lenguaje de sistemas. Cargo es lo que debería haber sido CMake desde el principio.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Extraño profundamente la era de los Nokia. Tenía un 3310 que sobrevivió cosas que matarían cualquier iPhone moderno. Y la batería duraba una semana.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La durabilidad se sacrificó en el altar del diseño delgado. Ningún fabricante quiere ser el que hace el teléfono "gordo" aunque sea más resistente y con mejor batería.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El Motorola Defy era indestructible y tenía batería de tres días. Desapareció porque el mercado premium no lo valoraba y Motorola no supo posicionarlo.</p>', alex) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Hay un mercado para teléfonos rugged tipo CAT o Blackview pero nunca van a ser mainstream porque la industria ya apostó todo al vidrio y aluminio pulido.</p>', noelia) RETURNING id INTO r4;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r4, '<p>El problema es que el vidrio en la parte trasera es una decisión de carga inalámbrica, no de diseño. Pero la percepción premium del vidrio vende más que la practicidad.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La homogeneización también llegó al software. Con Android skinned por cada fabricante al mismo aspecto y iOS, todas las interfaces convergen hacia lo mismo.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Samsung One UI es tan bueno ahora que ya no veo diferencia significativa con stock Android. Lo que antes era una razón para elegir Pixel ya no lo es tanto.</p>', noelia) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Excepto las actualizaciones. Pixel sigue siendo el rey del software support. 7 años de actualizaciones es algo que Samsung todavía no iguala en la práctica.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Los plegables son el primer intento real de diferenciación de forma en años. No sé si el Z Fold es el futuro pero al menos alguien intentó algo diferente.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La cámara es el único campo de diferenciación real ahora. Y aun así, las fotos de cualquier flagship de 2024 son tan buenas que las diferencias son académicas para el 99% de usuarios.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Los resultados de los ensayos para anemia falciforme son extraordinarios. Pacientes que necesitaban transfusiones regulares ahora llevan años sin una sola. Eso es medicina transformadora real.</p>', hannah) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El problema es el costo. Los primeros tratamientos de CRISPR aprobados cuestan millones de dólares. La tecnología funciona pero la accesibilidad es cero en la práctica global.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Igual pasó con los antiretrovirales para VIH. En los 90 eran inaccesibles, hoy son genéricos en países en desarrollo. La escala eventualmente reduce costos.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>El problema es que CRISPR para cada enfermedad requiere un desarrollo específico. No es como una pastilla genérica. La personalización eleva el costo estructuralmente.</p>', hannah) RETURNING id INTO r4;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r4, '<p>Los avances en delivery del sistema CRISPR in vivo (sin extraer células) podrían cambiar eso. Si puedes editar directamente en el cuerpo, la logística se simplifica enormemente.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El caso He Jiankui me parece el ejemplo perfecto de por qué necesitamos regulación internacional seria. El tipo actuó solo, fuera de todo protocolo ético, y creó dos seres humanos editados sin su consentimiento.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y lo que hizo puede tener consecuencias para esas personas que no conoceremos por décadas. Están vivas en algún lugar con ediciones no auditadas en su genoma.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El consenso científico fue rápido y unánime en condenarlo. Eso da esperanza de que la comunidad científica puede autorregularse, pero necesita respaldo legal con dientes reales.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La distinción entre terapéutico y enhacement es el debate más importante. Curar distrofia muscular: claro que sí. Elegir inteligencia o altura para tu hijo: terreno muy diferente.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Pero esa línea es filosóficamente difícil. ¿La miopía severa es enfermedad o variación? ¿La predisposición a depresión? El debate sobre dónde trazar la línea es genuinamente difícil.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La hipótesis del Gran Filtro me parece la más aterradora y la más plausible. Si el filtro está detrás de nosotros, somos extraordinariamente raros y afortunados. Si está adelante, tenemos un problema enorme.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Robin Hanson lo explica mejor que nadie: encontrar vida compleja en Marte sería una de las peores noticias posibles para la humanidad porque indicaría que el filtro está adelante.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Esa inversión contraintuitiva siempre me vuela la cabeza. La buena noticia de encontrar vida sería en realidad la peor noticia posible para nuestro futuro.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Aunque también podría indicar que la vida es ubicua y el filtro está en la transición a vida inteligente o tecnológica, no en la vida simple. Lo cual nos dejaría relativamente optimistas.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La hipótesis del silencio oscuro de Liu Cixin me parece literariamente brillante aunque científicamente especulativa. Civilizaciones que se esconden porque revelar su existencia es suicida. El universo como selva oscura.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El Problema de los Tres Cuerpos lo explora de manera fascinante. Pero tiene un problema lógico: una civilización suficientemente avanzada no necesitaría temer a otra.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>A menos que el universo tenga niveles tecnológicos con saltos tan grandes que incluso mil años de ventaja te hacen invulnerable. Lo cual convierte cualquier civilización joven en presa potencial.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Personalmente me quedo con la explicación más simple: la vida inteligente es extremadamente rara. El salto de organismos unicelulares a multicelulares, o a neuronas, puede ser tan improbable que ocurrió una sola vez.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El SETI lleva décadas buscando y nada. O están ahí y no transmiten, o no están. Ockham me dice que lo segundo es más probable.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Disco Elysium es el ejemplo perfecto de por qué los indie ganan el debate de la innovación. Ningún AAA hubiera financiado ese juego. Es demasiado raro, demasiado literario, demasiado político.</p>', hannah) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y sin embargo encontró su audiencia y fue aclamado universalmente. El mercado tiene espacio para lo experimental cuando los costos de producción son manejables.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El problema es que Disco Elysium casi mató a ZA/UM como estudio. Los despidos del equipo original después del éxito fueron una de las historias más tristes de la industria reciente.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Eso ilustra que el éxito crítico y artístico no protege a los creadores en una industria donde el capital puede expropiar el trabajo creativo. El problema no es AAA vs indie sino la estructura de propiedad.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Los AAA innovan en tecnología y escala aunque no en diseño. Ningún indie puede hacer lo que hace RDR2 en términos de mundo simulado o lo que hace God of War en producción cinematográfica.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Pero esa innovación tecnológica cada vez importa menos al jugador promedio. Después de cierto umbral visual, más polígonos no mejoran la experiencia emocional del juego.</p>', noelia) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Stardew Valley y Minecraft lo demuestran definitivamente. Gráficos simples, jugabilidad infinita. El realismo fotográfico es una carrera armamentista que no nadie pidió.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El último indie que me sorprendió fue Caves of Qud. Un roguelike de ciencia ficción con profundidad de lore comparable a Tolkien. Imposible que un AAA lo hiciera.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Hades cambió mi perspectiva sobre los roguelikes. Pensaba que el género era para masoquistas y resultó ser el juego más rejugable que he tocado en años.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Aplico la regla de las dos horas: si un juego no me engancha en las primeras dos horas, lo borro sin culpa. La vida es corta y el backlog es infinito.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Esa regla es liberadora pero también te hace perderte joyas de slow burn. Disco Elysium tarda cuatro horas en calentarse. La primera hora es torpe y confusa.</p>', noelia) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Para esos casos necesitas recomendaciones de personas que sepan que el juego tiene slow start. No puedes descubrirlos por ti mismo con esa regla.</p>', hannah) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Exacto, la curaduría social se vuelve más valiosa cuanto más grande es el catálogo. No lees todos los libros del mundo, lees recomendados por personas de confianza.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El Game Pass cambió mi relación con los juegos de manera negativa. Antes compraba pocos juegos y los terminaba porque había invertido dinero. Ahora tengo 200 títulos y no termino ninguno.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El efecto diderot digital. Tener muchas opciones paraliza en lugar de liberar. La paradoja de la elección aplicada a los videojuegos.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Barry Schwartz lo predijo: más opciones no significa más satisfacción, significa más ansiedad sobre la elección incorrecta y arrepentimiento post-elección.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Mi solución: me permito solo un juego activo a la vez. Cuando lo termino o lo abandono conscientemente, empiezo el siguiente. Cero multitasking de juegos.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Los juegos de 100+ horas son el problema real. Elden Ring, Baldur Gate 3, Cyberpunk. Son masterpieces pero me piden un compromiso de tiempo que ya no puedo dar con trabajo y familia.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Los experimentos piloto de RBU en Finlandia, Kenya y Stockton California muestran consistentemente que la gente no deja de trabajar. Usan el dinero para educarse, cuidar hijos o iniciar pequeños negocios.</p>', hannah) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El experimento de Finlandia fue limitado en escala y duración. No puedes extrapolar comportamiento sistémico de pilotos pequeños con conocimiento de que son temporales.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Cierto pero el de Kenya lleva más tiempo y a mayor escala. GiveDirectly ha dado transferencias durante años y el desarrollo económico local es medible y positivo.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Kenya y Finlandia son contextos tan diferentes que comparar sus resultados es metodológicamente cuestionable. El impacto depende enormemente del mercado laboral local.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El empleo garantizado me parece más realista políticamente. Es más fácil convencer a una sociedad de pagar trabajo que de dar dinero sin condiciones. La ética protestante del trabajo sigue dominando el imaginario político.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Eso es exactamente el problema. Las políticas se diseñan según lo que es políticamente vendible, no según lo que funciona. Y lo que funciona puede ser contraintuitivo.</p>', noelia) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque también importa la legitimidad. Una política que la mayoría percibe como injusta genera resistencia que la hace ineficaz aunque sea técnicamente superior.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La automatización va a forzar esta conversación de todas maneras. No es si vamos a necesitar una respuesta sino cuándo. Mejor debatirlo ahora que en medio de una crisis.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Andrew Yang llevó la RBU al mainstream americano. Independientemente de lo que pienses de él, logró que millones de personas consideraran seriamente una idea que antes parecía fringe.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Trabajo en diseño y el brutalismo web es una reacción legítima al template design que domina Webflow y Squarespace. Cuando todos usan las mismas plantillas, salirse del molde tiene valor comunicativo real.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Pero ¿es la ruptura del molde el mensaje en sí mismo? Mucho brutalismo parece más interesado en demostrar que rompe reglas que en comunicar algo con esa ruptura.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Igual que el punk musical. Mucho era ruido sin contenido pero algunos grupos usaron la estética para decir cosas genuinas. La estética en sí no es válida o inválida, depende del uso.</p>', hannah) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Buena analogía. El Clash usó la estética punk para hacer algo con sustancia. The Exploited era pura pose. El brutalismo web tiene sus Clash y sus Exploited también.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La accesibilidad es mi objeción principal. Tipografías enormes y contrastes agresivos pueden ser problemáticos para personas con dislexia o sensibilidad visual. El diseño no puede ser solo para los neurotípicos.</p>', hannah) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Punto válido. El diseño inclusivo y el diseño llamativo no son mutuamente excluyentes pero en la práctica el brutalismo suele priorizar el impacto visual sobre la accesibilidad.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Bloomberg Businessweek es el ejemplo de brutalismo bien ejecutado. Impactante visualmente pero completamente legible y accesible. No es imposible hacer ambas cosas.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>En arquitectura el brutalismo fue una tendencia con consecuencias físicas que duran décadas. Los edificios brutalistas de los 60-70 están en debates de demolición vs preservación. El web brutalismo al menos es efímero.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Colecciono vinilos desde hace 10 años y lo que más valoro no es el sonido sino la atención. Con streaming saltas canciones sin pensarlo. Con vinilo escuchas el lado completo porque levantarte a cambiarlo tiene fricción.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Eso es profundo. El vinilo impone escucha activa por diseño. Es el opuesto al shuffle eterno de Spotify.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Los artistas lo saben y algunos diseñan sus álbumes pensando en el formato. La secuencia de lados importa. Kendrick Lamar y Taylor Swift han hablado de eso explícitamente.</p>', alex) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>El álbum como unidad narrativa casi murió con el streaming. El vinilo es uno de los pocos formatos que te obliga a escucharlo como el artista lo concibió.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El debate del sonido es interminable pero honestamente para la mayoría de sistemas de audio el vinilo no suena mejor que un FLAC bien masterizado. Lo que suena diferente es el warmth analógico que algunos prefieren.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El "sonido cálido" del vinilo es en parte armónicos que añade el proceso analógico. Técnicamente son distorsiones. Pero algunas distorsiones suenan bien a nuestro oído.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Igual que la compresión de los tubes en amplificadores valvulares. Son imperfecciones que el cerebro procesa como placenteras. La fidelidad perfecta no siempre es el objetivo.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El vinilo también es el único formato físico que ha sobrevivido la digitalización. El CD está prácticamente muerto. El cassette resurgió como nostalgia hipster pero es marginal. El vinilo tiene masa crítica real.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La última que compré fue Rumours de Fleetwood Mac en una edición remasterizada. Escucharla en vinilo con una copa de vino es una experiencia que Spotify no puede replicar por más algoritmos que use.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Sophie fue la figura más importante del hyperpop y su muerte fue una pérdida enorme para la música experimental. Product y Oil of Every Pearl son obras de arte genuinas aunque suenen a glitch.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Sophie llevaba el hyperpop hacia algo más serio y político. Había una dimensión de crítica al consumismo y al género en su trabajo que 100 gecs no tiene.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>100 gecs es más punk que hyperpop en el sentido de que la irreverencia es el punto. Sophie tenía algo que decir además de la forma. Son proyectos muy diferentes aunque compartan estética.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Charli XCX con Brat encontró la manera de llevar la estética hyperpop al mainstream sin diluirla completamente. Es un equilibrio rarísimo que pocos artistas logran.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Lo que me fascina del hyperpop es que tomó la estética Y2K del pop más comercial y la llevó al límite hasta hacerla rara de nuevo. Es pop que se mockea a sí mismo siendo pop.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Esa autoconciencia es lo que lo distingue del simple glitch o noise. Sabe exactamente lo que es y juega con esa identidad. Es pop posmoderno en el sentido más literal.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque el posmodernismo tiene el problema de agotarse a sí mismo. Cuando la autorreferencia es el único recurso, ¿hacia dónde va después? Arca ya está empujando más allá.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Lo escucho en sesiones específicas, no de fondo. Requiere atención activa o se convierte en ruido irritante. Que un género requiera escucha activa para funcionar me parece respetable aunque sea extenuante.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Victor Wembanyama es la respuesta más obvia y probablemente correcta. Combina capacidades que ningún jugador ha tenido: altura de centro con habilidades de guardia y defensa transformacional. Si se mantiene sano, redefinirá el juego.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El si se mantiene sano es enorme. Los jugadores de 7 pies con ese wingspan histórica tienen problemas de durabilidad. El cuerpo no está diseñado para esas proporciones en 82 partidos por temporada.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>KAT, Jokic, KD tienen proporciones similares y han sido durables. La correlación entre altura extrema y lesiones es real pero no determinista.</p>', alex) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Jokic es el argumento más convincente de que el next era player es un big con habilidades de playmaker. Y Wemby es Jokic pero con atletismo y defensa de otro planeta.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>SGA en Oklahoma City está construyendo algo especial. Liderando un equipo joven con el mejor record de la liga sin ser el nombre más famoso. Ese tipo de liderazgo silencioso suele predecir grandeza.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>SGA tiene el perfil ofensivo para ser dominante pero me preocupa si OKC puede construir un equipo ganador de título a su alrededor. Tiene el mismo problema que Durant en OKC original.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>OKC tiene los activos para mejorar el roster cuando llegue el momento. Sam Presti es el mejor GM de la liga. Confío más en ese front office que en casi cualquier otro.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Luka Doncic ya demostró que puede ser el mejor jugador del mundo en las finales aunque Dallas perdiera. Eso es el tipo de performance que define eras.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El problema de Luka es siempre la defensa y el físico. Lleva años siendo criticado por lo mismo. En los playoffs eso se amplifica y equipos como Boston lo explotan sistemáticamente.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La decisión de Villeneuve de hacer de Chani una escéptica fue brillante. En el libro es una creyente pasiva. En la película su arco dramático le da una voz crítica a la narrativa mesiánica que el libro solo implica.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y eso hace que el arco de Paul sea más trágico. El libro es ambiguo sobre si Paul es héroe o villano. La película hace más explícito que Paul elige el poder sobre la verdad.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Herbert escribió Dune específicamente como una crítica al mesianismo y al héroe carismático. Villeneuve lo entiende y eso se nota en cada decisión narrativa de Parte 2.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>La mayoría de las adaptaciones de Dune antes de Villeneuve no entendían eso. Lynch hizo a Paul un héroe sin ambigüedad y perdió el corazón del libro.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Zendaya como Chani funcionó mucho mejor de lo que esperaba. Tenía mis dudas pero su actuación en Parte 2 es genuinamente poderosa, especialmente en la escena final.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Austin Butler como Feyd-Rautha robó cada escena. La secuencia en la arena en blanco y negro es uno de los mejores momentos del cine de ciencia ficción reciente.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Hans Zimmer creó el score más alienante y brillante de su carrera. Esa música no suena a nada conocido. Construyó instrumentos nuevos para el proyecto. Eso es compromiso artístico.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Esperando Mesías con anticipación pero también nerviosismo. Dune Mesías es donde Herbert deconstruye completamente a Paul. Ver si Villeneuve tiene el valor de seguir esa dirección será fascinante.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La escala de Parte 2 en IMAX fue una de las mejores experiencias cinematográficas de mi vida. El desierto de Arrakis se siente real y aplastante de una manera que solo el cine puede lograr.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Mi primer viaje solo fue a Japón y fue terrorífico e increíble en igual medida. No hablar el idioma y tener que resolver cada cosa por ti mismo construye una confianza que ningún otro tipo de viaje da.</p>', hannah) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Japón es paradójicamente uno de los mejores países para viajar solo siendo extranjero. Todo es señalizado, seguro y la gente te ayuda aunque no compartas idioma.</p>', alex) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque esa misma característica puede hacer que no salgas de tu zona de confort. Es tan fácil y cómodo que no te obliga a improvisar tanto como en lugares más caóticos.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>India o Marruecos solo son otro nivel de inmersión. El caos te obliga a estar presente de una manera que los destinos hiper-organizados no permiten.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Lo que nadie te dice del viaje solo es la soledad real. No la soledad romántica de Instagram sino el momento en un restaurante donde ves a familias y grupos y sientes un vacío genuino.</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Ese momento es parte del proceso. Aprender a estar cómodo con tu propia compañía en situaciones sociales es una habilidad que se desarrolla exactamente así.</p>', noelia) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Los hostales ayudan con eso. La cultura de los hostales crea conexiones efímeras pero reales. Conoces gente con quien compartes 48 horas intensas y luego nunca vuelves a ver.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El viajar solo te revela aspectos de tu carácter que no sabías que tenías. Cómo reaccionas cuando las cosas salen mal sin una red de apoyo cerca dice mucho sobre quién eres.</p>', noelia);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Recomiendo hacerlo al menos una vez antes de los 30. No porque después sea imposible sino porque antes tienes más tolerancia al riesgo y más tiempo para procesar lo que aprendes.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El argumento de Bostrom es lógicamente válido pero la premisa de que civilizaciones avanzadas querrían simular ancestros me parece débil. ¿Por qué asumir que nuestros intereses proyectan hacia el futuro?</p>', alex) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Aunque el argumento no requiere que la mayoría lo haga, solo que algunos lo hagan. Si hay millones de civilizaciones avanzadas y una pequeña fracción crea simulaciones, el número de simulaciones supera al de realidades base.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Esa probabilidad solo funciona si asumes uniformidad de distribución entre entidades conscientes. Si las simulaciones tienen mucho menos consciencias que la realidad base, el argumento se debilita.</p>', noelia) RETURNING id INTO r3;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Max Tegmark y Sean Carroll son escépticos por razones físicas: para simular física cuántica a nivel fundamental necesitarías más capacidad computacional que la que el universo observable contiene.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La pregunta práctica es: ¿cambia algo si vivimos en una simulación? Si las leyes físicas son consistentes y las experiencias son reales para nosotros, la distinción entre simulado y real se vuelve filosóficamente vacía.</p>', noelia) RETURNING id INTO r1;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Exacto. Es la misma respuesta pragmatista de siempre. Si no hay diferencia observable no hay diferencia práctica. El solipsismo tiene la misma respuesta.</p>', hannah) RETURNING id INTO r2;
    INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>A menos que los creadores de la simulación puedan intervenir, en cuyo caso sí tiene consecuencias prácticas enormes. Es la pregunta sobre si hay "glitches" detectables en las leyes físicas.</p>', alex);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Elon Musk creyendo en la hipótesis de la simulación con certeza me hace desconfiar de ella. Cuando algo se convierte en identidad de grupo de tech bros, suele haber más ego que epistemología.</p>', hannah);
    INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La física del universo teniendo constantes aparentemente ajustadas fine-tuned para permitir la complejidad es el mejor argumento para la simulación que existe. Aunque también es argumento para el diseño inteligente, lo cual es incómodo.</p>', noelia);
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Libros y Literatura', 'Novela, ensayo, poesía y todo el mundo de la palabra escrita', 'libros-literatura', '📚', noelia) RETURNING id INTO ch_libros;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Salud y Bienestar', 'Nutrición, ejercicio, salud mental y hábitos de vida saludable', 'salud-bienestar', '🏃', hannah) RETURNING id INTO ch_salud;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Finanzas Personales', 'Inversión, ahorro, presupuesto y libertad financiera', 'finanzas-personales', '💰', alex) RETURNING id INTO ch_finanzas;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Cocina y Gastronomía', 'Recetas, técnicas, ingredientes y cultura culinaria', 'cocina-gastronomia', '🍳', noelia) RETURNING id INTO ch_cocina;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Historia', 'Eventos históricos, civilizaciones antiguas y lecciones del pasado', 'historia', '🏛️', alex) RETURNING id INTO ch_historia;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Educación', 'Métodos de aprendizaje, sistema educativo y autoeducación', 'educacion', '🎓', hannah) RETURNING id INTO ch_educacion;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Medio Ambiente', 'Cambio climático, sostenibilidad y ecología', 'medio-ambiente', '🌱', noelia) RETURNING id INTO ch_medio_amb;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Emprendimiento', 'Startups, negocios, productividad y mentalidad emprendedora', 'emprendimiento', '🚀', alex) RETURNING id INTO ch_emprender;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Psicología', 'Comportamiento humano, terapia, sesgos cognitivos y salud mental', 'psicologia', '🧩', hannah) RETURNING id INTO ch_psicologia;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Anime y Manga', 'Series, películas, manga y cultura otaku', 'anime-manga', '⛩️', noelia) RETURNING id INTO ch_anime;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Cómics y Novela Gráfica', 'Marvel, DC, independientes y la novela gráfica como arte', 'comics', '💥', alex) RETURNING id INTO ch_comics;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Fotografía', 'Técnica, composición, equipos y fotógrafos que inspiran', 'fotografia', '📷', hannah) RETURNING id INTO ch_fotografia;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Arquitectura y Espacios', 'Diseño urbano, arquitectura moderna y espacios que habitan la historia', 'arquitectura', '🏗️', noelia) RETURNING id INTO ch_arquitect;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Moda y Estilo', 'Tendencias, diseñadores, streetwear y la moda como expresión', 'moda-estilo', '👗', alex) RETURNING id INTO ch_moda;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Podcasts y Audio', 'Recomendaciones, creación de contenido y la era del audio', 'podcasts-audio', '🎙️', hannah) RETURNING id INTO ch_podcasts;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Idiomas', 'Aprendizaje de idiomas, lingüística y comunicación intercultural', 'idiomas', '🗣️', noelia) RETURNING id INTO ch_idiomas;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Crypto y Web3', 'Bitcoin, Ethereum, DeFi y el futuro de las finanzas descentralizadas', 'crypto-web3', '₿', alex) RETURNING id INTO ch_crypto;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Exploración Espacial', 'NASA, SpaceX, misiones y el futuro de la humanidad en el cosmos', 'exploracion-espacial', '🚀', hannah) RETURNING id INTO ch_espacio;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Robótica e IA Aplicada', 'Robots, automatización, machine learning y sus aplicaciones reales', 'robotica-ia', '🤖', alex) RETURNING id INTO ch_robotica;
  INSERT INTO channels (name, description, slug, icon, created_by) VALUES ('Teatro y Artes Escénicas', 'Teatro, danza, ópera y las artes que viven en el presente', 'teatro-artes-escenicas', '🎭', noelia) RETURNING id INTO ch_teatro;
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_libros, '¿Ha muerto la novela larga? El problema del lector contemporáneo con la atención', '<p>Proust, Tolstoi, Dostoievski. Los grandes monumentos de la literatura occidental requieren semanas de lectura sostenida y atención profunda que el lector moderno encuentra cada vez más difícil de mantener. No porque seamos más tontos sino porque vivimos en un ecosistema de atención fragmentada.</p><p>¿Siguen siendo relevantes las novelas de 800 páginas o son artefactos de una era donde el entretenimiento no competía con TikTok?</p>', noelia) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La novela larga no ha muerto, ha encontrado su audiencia natural. Siempre fue un entretenimiento de nicho comparado con el teatro o la música. Lo que murió es la ilusión de que era el entretenimiento masivo por defecto.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Buen punto histórico. En el siglo XIX las novelas por entregas de Dickens eran el Netflix de la época. Ese rol masivo no va a volver pero el medio sigue vivo para quienes lo buscan.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La diferencia es que antes no había competencia. Ahora compite con series, juegos, podcasts, redes sociales. Que siga teniendo audiencia comprometida en ese contexto es notable.</p>', noelia) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Y las ventas de libros físicos llevan años creciendo. La gente que lee, lee más que nunca. El grupo medio que leía por obligación social desapareció pero los lectores genuinos permanecen.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Leí los siete tomos de En busca del tiempo perdido el año pasado. Tardé ocho meses. Fue la experiencia cultural más intensa de mi vida adulta y no cambiaría ese tiempo por ninguna serie.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Proust es el mejor argumento para la novela larga. No puedes comprimir lo que hace en menos espacio. La lentitud es la forma, no un defecto.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque hay lectors que lo abandonan precisamente por eso. La fricción es parte del diseño pero también es una barrera real de entrada para mucha gente.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Mi solución es leer antes de dormir sin teléfono cerca. Treinta minutos diarios sin interrupción avanzan cualquier novela en semanas. La clave es eliminar la competencia de atención, no esforzarte más.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El audiolibro como formato democratizó el acceso a novelas largas para personas que no tienen tiempo de sentarse a leer. No es lo mismo pero tampoco es menos válido.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_libros, 'Recomendaciones: los mejores libros de no ficción de la última década', '<p>La no ficción ha tenido una década extraordinaria. Desde Sapiens hasta El Mundo Después de la Medianoche, pasando por When Breath Becomes Air y Thinking Fast and Slow. ¿Cuáles son sus recomendaciones imprescindibles?</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El mundo de ayer de Stefan Zweig. Técnicamente de 1942 pero sigue siendo el mejor retrato de cómo una civilización puede destruirse a sí misma que he leído. Releído dos veces.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Zweig es devastador porque escribe desde dentro de la catástrofe sin saber el final. Esa sensación de mundo que se acaba tiene una intensidad que la historia escrita después no puede replicar.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La paradoja de Zweig es que su prosa optimista y humanista contrasta con el contexto de derrumbe total que describe. Esa tensión hace el libro insoportablemente bello.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Thinking Fast and Slow de Kahneman cambió permanentemente cómo pienso sobre mis propias decisiones. Entender Sistema 1 y Sistema 2 es una de esas ideas que no puedes des-aprender.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Aunque hay que leerlo con escepticismo. Muchos de los estudios que cita han tenido problemas de replicación. La crisis de replicación en psicología afecta bastante al libro.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Cierto pero el marco conceptual del Sistema 1/2 sigue siendo válido aunque algunos ejemplos específicos fallen. La idea central es robusta aunque los detalles sean cuestionables.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Being Mortal de Atul Gawande sobre la muerte y los cuidados paliativos. Cambió cómo pienso sobre el final de la vida de una manera que ninguna conversación con médicos había logrado.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El gen de Siddhartha Mukherjee. Biología molecular accesible con narrativa de thriller. Explica CRISPR y la historia de la genética mejor que cualquier divulgación científica que haya leído.</p>', noelia);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_salud, 'El sueño es la inversión de salud más subestimada: lo que dice la ciencia', '<p>Matthew Walker en Por qué dormimos sistematizó décadas de investigación sobre el sueño y el resultado es alarmante. Prácticamente cada sistema del cuerpo se deteriora con privación crónica de sueño. El cerebro literalmente se limpia de desechos metabólicos durante el sueño profundo. Sin ese proceso, el riesgo de Alzheimer aumenta.</p><p>¿Cómo protegen su sueño en un mundo que glorifica dormir poco?</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Lo más transformador fue entender que el sueño no es un lujo sino mantenimiento biológico obligatorio. Una vez que lo ves así, priorizar 8 horas deja de sentirse como pereza y pasa a ser higiene básica.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El problema es la cultura laboral que glorifica sacrificar sueño como señal de dedicación. Ejecutivos que duermen 4 horas como badge of honor. Es el equivalente a presumir de no lavarse los dientes.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Jeff Bezos ha dicho públicamente que duerme 8 horas y lo prioriza. Que uno de los empresarios más exitosos del mundo sea vocal sobre esto debería hacer reflexionar a la cultura del hustle.</p>', hannah) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Aunque Bezos también construyó Amazon con una cultura de trabajo brutal para sus empleados. Que él duerma bien mientras exige lo contrario de su empresa es una hipocresía notable.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La temperatura de la habitación es el cambio más impactante que hice. Bajar el cuarto a 18-19 grados mejora dramáticamente la calidad del sueño profundo. El cuerpo necesita bajar su temperatura central para entrar en sueño reparador.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Confirmado por meses de datos con Oura Ring. Las noches más frías son consistentemente mis noches con más sueño profundo. La correlación es clara.</p>', hannah) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El problema en México en verano es que hacer eso sin AC es imposible y con AC la factura se convierte en un factor de estrés que también afecta el sueño. El bienestar tiene costos de acceso desigual.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La luz azul en las noches es real pero creo que está sobreestimado comparado con simplemente tener una hora consistente de dormir y despertar. La regularidad del ritmo circadiano es más impactante que el f.lux.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El libro de Walker es excelente pero algunos investigadores del sueño lo critican por exagerar ciertos riesgos. La ciencia del sueño es más matizada que su presentación. Sigue siendo válido en líneas generales.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_salud, 'Correr vs levantar pesas: el debate que no debería ser un debate', '<p>Durante años el cardio fue el dogma del fitness y después los pesos se convirtieron en la nueva religión. La realidad es que ambos tienen beneficios únicos y complementarios que ninguno puede reemplazar por sí solo.</p><p>¿Cómo estructuran su entrenamiento? ¿Han encontrado el equilibrio entre ambos tipos de ejercicio?</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La zona 2 de cardio para salud mitocondrial y cardiovascular, más entrenamiento de fuerza dos veces por semana. Peter Attia lo explica mejor que nadie y los datos respaldan que esta combinación es la más efectiva para longevidad.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La zona 2 es el gran descubrimiento del fitness de los últimos años. Intensidad moderada sostenida, no el HIIT de alta intensidad que se puso de moda. Caminata rápida o ciclismo liviano durante 45 minutos es suficiente.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El problema es que la zona 2 es aburrida comparada con el HIIT. Y el compliance a largo plazo depende de que el ejercicio sea disfrutable. Mejor HIIT que haces que zona 2 que no haces.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Escuchar podcasts o audiolibros durante zona 2 resuelve el problema del aburrimiento. La hora más productiva de información que proceso en el día es mientras camino rápido.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La masa muscular es el factor más subestimado de la salud a largo plazo. Después de los 40 pierdes 1% de músculo por año sin entrenamiento de fuerza. Esa pérdida acumulada predice mortalidad mejor que casi cualquier otro marcador.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Sarcopenia es la epidemia silenciosa. Nadie habla de ella comparado con la obesidad pero sus efectos en calidad de vida de adultos mayores son devastadores y completamente prevenibles con ejercicio.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Mi abuela de 75 años hace pesas dos veces por semana desde los 60 y tiene mejor funcionalidad que muchas personas de 55. El ejercicio de fuerza en adultos mayores debería ser prescripción médica rutinaria.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Nadie habla del yoga y la movilidad como categoría separada. La flexibilidad y el rango de movimiento predicen caídas en adultos mayores igual que la fuerza. El fitness completo incluye las tres dimensiones.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El mejor ejercicio es el que haces consistentemente. Puedo darte el programa óptimo de Peter Attia pero si lo odias y lo abandonas en un mes, caminar 30 minutos diarios es infinitamente mejor.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_finanzas, 'Index funds vs stock picking: por qué el 90% de los inversores activos pierden con el índice', '<p>El dato más contraintuitivo de las finanzas personales es que la mayoría de los gestores profesionales, con acceso a información privilegiada y equipos de análisis, no baten al índice S&P 500 a largo plazo. Sin embargo millones de inversores individuales creen poder hacer lo que los profesionales no pueden.</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Jack Bogle creó Vanguard y los index funds para democratizar el acceso a retornos de mercado. La idea de que no necesitas pagar a un gestor para obtener retornos de mercado era revolucionaria y los datos después de 50 años son concluyentes.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Lo más poderoso no es solo que los índices baten a los gestores activos. Es que el bajo costo de los índices significa que aunque un gestor te bata por 1%, sus comisiones se comen ese 1% y más.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El efecto del costo en el interés compuesto a 30 años es devastador. Un 1% de diferencia en comisiones puede representar el 25% del portafolio final. La gente no lo visualiza porque los porcentajes se sienten pequeños.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Un VTI o un VWCE y olvidarse durante 30 años es literalmente la estrategia óptima para el 99% de inversores individuales. Todo lo demás es entretenimiento disfrazado de inversión.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El problema psicológico del índice es que es aburrido. El stock picking te da la ilusión de control y el placer de la investigación. El cerebro no está diseñado para "no hacer nada" con algo tan importante como tu dinero.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Por eso Morgan Housel dice que la psicología del dinero importa más que las matemáticas. Una estrategia subóptima que puedes mantener emocionalmente es mejor que la estrategia óptima que abandonas en pánico.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La única forma de saber si puedes aguantar una caída del 50% es haberla experimentado. El March 2020 eliminó a muchos inversores que creían tener tolerancia al riesgo.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>En México el acceso a ETFs de índices globales es limitado sin una cuenta en el extranjero. GBM y otros brokers tienen opciones pero las comisiones siguen siendo mayores que Fidelity o Vanguard en USA.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El mejor libro sobre esto es La Psicología del Dinero de Morgan Housel. Corto, brillante, cambia la relación con el dinero de maneras que los libros técnicos no logran.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_finanzas, 'El fondo de emergencia: cuánto es suficiente y dónde guardarlo', '<p>La recomendación estándar de 3-6 meses de gastos en efectivo tiene matices importantes según tu situación. Un freelancer necesita más que un empleado con contrato fijo. Una persona con dependientes necesita más que alguien solo.</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Lo que nadie te dice es que el fondo de emergencia en cuenta de ahorro tradicional está perdiendo poder adquisitivo vs inflación. En México con inflación del 4-5% anual y cuentas al 1%, estás perdiendo dinero en términos reales.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Las cuentas de alta rentabilidad como Nu, Mercado Pago o GBM+ ofrecen tasas mucho mejores vinculadas a CETES. El fondo de emergencia puede generar rendimiento real sin perder liquidez.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>CETES directo también. Para montos mayores, CETES a 28 días ofrece liquidez casi inmediata con tasas competitivas. El gobierno mexicano es el emisor más seguro posible.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Siendo freelance mantengo 8 meses de gastos. La irregularidad del ingreso hace que el estándar de 3-6 sea insuficiente. Perder un cliente grande puede significar meses sin ingresos antes de reemplazarlo.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La diversificación de clientes es la mejor protección para un freelance, más que el tamaño del fondo. Que ningún cliente represente más del 30% de tus ingresos reduce dramáticamente la volatilidad.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Dicho fácil, hecho difícil. Cuando tienes un cliente que paga bien y consistentemente, el incentivo para buscar diversificación es bajo hasta que ese cliente desaparece.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El fondo de emergencia psicológico vale más que el financiero. Saber que tienes colchón cambia cómo tomas decisiones laborales. Puedes rechazar clientes malos, negociar mejor, renunciar a empleos tóxicos.</p>', hannah);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_cocina, 'El mito del tiempo: cocinar bien no necesita horas, necesita técnica', '<p>La excusa más común para no cocinar en casa es la falta de tiempo. Pero con técnica básica, mise en place y buenas recetas, comer bien en casa puede ser más rápido que pedir delivery y infinitamente más económico.</p>', noelia) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El meal prep del domingo cambió mi vida. Tres horas el domingo y como bien toda la semana sin esfuerzo diario. La cocina batch es la técnica más subestimada de la cocina casera.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Granos cocidos, proteína marinada, verduras lavadas y cortadas. Con esos tres elementos puedes armar comidas distintas cada día en 15 minutos. El trabajo es la preparación, no la cocción diaria.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La parrilla y el horno son los grandes aliados del cook batch. Puedes asar cinco pechugas al mismo tiempo que cueces arroz y horneas verduras. El tiempo de cocción es el mismo para uno que para cinco.</p>', noelia) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>El conocimiento del punto de cocción es lo que hace la diferencia. Saber cuándo está listo sin cortar ni adivinar requiere experiencia pero transforma completamente la cocina cotidiana.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Tener un buen cuchillo afilado reduce el tiempo de preparación a la mitad. Gente que dice que cocinar tarda mucho a menudo está usando herramientas malas. Un Global o Victorinox básico cambia la experiencia.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y aprender a afilar. Un cuchillo nuevo mal mantenido en seis meses es peor que uno barato afilado. El afilado es la habilidad más subestimada de la cocina doméstica.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Piedra de afilar japonesa o simplemente llevar los cuchillos a afilar periódicamente. En muchos mercados hay afiladores que lo hacen por muy poco dinero. No hay excusa.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Saber hacer cuatro o cinco recetas muy bien es suficiente para comer estupendo toda la vida. Muchas personas buscan variedad infinita cuando la maestría de lo básico es lo que hace la diferencia.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El Maillard es la técnica más importante que nadie enseña en casa. Dorar proteínas y verduras correctamente genera sabor que ningún condimento puede reemplazar. La costra marrón es el objetivo.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_cocina, 'Fermentación casera: el hobby que mejora tu cocina y tu microbioma', '<p>Kombucha, kéfir, kimchi, sourdough, miso. La fermentación experimentó un renacimiento en la cocina doméstica en los últimos años. No solo como hobby sino como práctica de salud con evidencia científica creciente sobre el microbioma intestinal.</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Empecé con sourdough durante la pandemia como todos y nunca paré. La ciencia detrás de la fermentación láctica es fascinante y el pan que produces es incomparablemente mejor que cualquier pan comercial.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El sourdough es el mejor gateway a la fermentación porque los resultados son inmediatamente deliciosos y visibles. Ver crecer el starter por primera vez tiene algo casi mágico.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La ciencia del gluten y la fermentación también ayuda a entender por qué el pan industrial es diferente. La fermentación lenta rompe el gluten de maneras que hacen el pan más digerible.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Kimchi casero es la mejor introducción a la fermentación de verduras. Más rápido que el chucrut, con sabores más complejos y la tradición coreana tiene cientos de años de sabiduría detrás.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El estudio de Stanford de 2021 comparando dieta alta en fermentados vs dieta alta en fibra encontró que los fermentados mejoraban la diversidad del microbioma más consistentemente. El kimchi tiene respaldo científico serio ahora.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Con la advertencia de que la ciencia del microbioma aún está en pañales. Sabemos que la diversidad microbiana es buena. Los mecanismos exactos de por qué y cómo son mucho menos claros.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El kéfir de leche es el fermentado más nutritivo y el más fácil de mantener. Los granos de kéfir se reproducen solos, no cuestan nada una vez que los tienes y el producto es probiótico real, no como los yogures pasteurizados.</p>', hannah);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_historia, 'El colapso de la Edad del Bronce: la primera gran civilización que desapareció', '<p>Alrededor del 1200 a.C., en menos de cincuenta años, prácticamente todas las grandes civilizaciones del Mediterráneo oriental colapsaron simultáneamente. Los micénicos, los hititas, el Imperio egipcio en su forma original, las ciudades-estado de Canaán. Es uno de los mayores misterios de la arqueología.</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El libro de Eric Cline 1177 a.C. es el mejor punto de entrada. Su argumento de que fue un colapso sistémico causado por la complejidad interconectada de las civilizaciones tiene ecos aterradores con el mundo moderno.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La analogía con las cadenas de suministro globales modernas es inevitable. El comercio de estaño desde Afganistán hacia el Mediterráneo era tan crítico como el semiconductor de Taiwan hoy. Cuando se interrumpe todo colapsa.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Y los Pueblos del Mar son el misterio dentro del misterio. ¿De dónde venían? ¿Eran una causa o también víctimas de un colapso más amplio que los obligó a migrar? La evidencia es contradictoria.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>La hipótesis climática también tiene peso. Análisis de polen y sedimentos muestran una megasecuencia de sequías en el Mediterráneo oriental justo en ese periodo. Las civilizaciones agrícolas colapsan con el agua.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Lo que más me impresiona es la velocidad. En 50 años desaparecieron sistemas que habían durado siglos. Las cartas de Amarna muestran reyes pidiendo ayuda mientras el sistema se desintegra. Es la historia del fin del mundo en documentos reales.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y la oscuridad que vino después. La Edad Oscura griega duró 400 años. La escritura desapareció. Cuando Homero escribió la Ilíada, estaba describiendo un mundo que llevaba siglos siendo leyenda.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La transmisión oral de la Ilíada durante 400 años de analfabetismo es en sí misma una historia fascinante sobre la resiliencia cultural y los límites de la memoria colectiva.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La lección más importante: las civilizaciones complejas e interconectadas son más productivas pero también más frágiles. La complejidad optimiza el rendimiento y aumenta el riesgo de colapso en cascada.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_psicologia, 'Terapia cognitivo-conductual vs terapia psicoanalítica: ¿importa el enfoque?', '<p>La TCC tiene la mayor base de evidencia empírica de cualquier modalidad psicoterapéutica. Sin embargo el psicoanálisis y las terapias psicodinámicas siguen siendo practicadas ampliamente y muchos pacientes reportan beneficios que la TCC no logró.</p><p>¿Han tenido experiencia con algún tipo de terapia? ¿Qué funcionó y qué no?</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Cinco años de TCC para ansiedad y fue transformador. La restructuración cognitiva me dio herramientas concretas para interrumpir patrones de pensamiento que tenía automatizados desde la infancia.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La TCC es excelente para trastornos específicos y bien definidos. Para cosas más difusas como el sentido de vida o relaciones complejas, los enfoques humanistas o psicodinámicos pueden ser más apropiados.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La investigación de Luborsky sobre el factor común sugiere que la alianza terapéutica importa más que el enfoque. Un buen terapeuta de cualquier escuela probablemente supera a uno mediocre de la escuela correcta.</p>', hannah) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Eso es liberador y frustrante al mismo tiempo. Significa que encontrar al terapeuta correcto es más importante que elegir el enfoque correcto. Y encontrar al correcto requiere prueba y error con costo humano y económico.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>EMDR para trauma es otra herramienta con evidencia robusta que no encaja limpiamente en ninguna de las dos categorías. La neurociencia del procesamiento traumático está revelando por qué funciona mecanismos que el psicoanálisis intuía sin poder explicar.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La integración de distintos enfoques es hacia donde va la terapia moderna. ACT, DBT, terapia somática. Los límites entre escuelas se están disolviendo en la práctica clínica actual.</p>', hannah) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque la integración sin formación sólida en cada enfoque puede ser eclecticismo superficial. Un terapeuta que hace un poco de todo sin profundidad puede ser menos efectivo que uno especializado.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El acceso es el elefante en la habitación. TCC basada en evidencia con un buen terapeuta cuesta dinero que no todos tienen. Las apps de meditación y los libros de autoayuda no son sustitutos pero son lo que está disponible para la mayoría.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La terapia online democratizó el acceso significativamente aunque perdió algo del componente presencial. Para muchas personas una buena sesión online es mejor que ninguna sesión.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_anime, 'Attack on Titan terminó: ¿el mejor final de la historia del anime?', '<p>Shingeki no Kyojin concluyó después de años de espera y generó uno de los debates más intensos en la comunidad otaku. El Rumbling, las decisiones de Eren, el final específico que eligió Isayama. Todo es controversial y todo tiene defensores apasionados.</p>', noelia) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El arco de Eren desde temporada 3 en adelante es uno de los escritos más ambiciosos del shonen. Convertir al protagonista en villano de manera gradual y retroactivamente coherente es un logro narrativo enorme.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La foreshadowing del final desde el primer capítulo del manga es extraordinaria cuando lo lees por segunda vez. Isayama tenía el final planificado desde el principio y los detalles escondidos son innumerables.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque hay lectores que argumentan que el final contradice la caracterización de Eren en arcos anteriores. El debate sobre si es brillante o inconsistente sigue activo en la comunidad.</p>', noelia) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>El Eren de 19 años que vio el futuro completo y eligió actuar así de todas formas es coherente si aceptas el determinismo de los Titanes. El problema es que requiere aceptar una premisa filosófica específica.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El Rumbling como genocidio que el protagonista ejecuta conscientemente para proteger a su pueblo es lo más oscuro que ha hecho un protagonista de shonen mainstream. Isayama se negó a resolver esa contradicción con facilidad.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y el anime lo adaptó con una dirección excepcional. La secuencia del Rumbling en la temporada final es visualmente impresionante pero emocionalmente agotadora de la manera correcta.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>MAPPA tuvo una producción caótica con crunch brutal según los animadores. Que el resultado sea tan bueno a pesar de eso es notable aunque las condiciones laborales sean inaceptables.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Para mí el mejor final sigue siendo FMA Brotherhood. AoT tiene ambición mayor pero la ejecución del final es más divisiva. FMA da cierre satisfactorio a cada personaje sin sacrificar la complejidad temática.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Hunter x Hunter sin final oficial sigue siendo el mayor crimen del anime moderno. Yoshihiro Togashi tiene uno de los mejores guiones de la historia del manga y no lo termina por problemas de salud. Tragedia real.</p>', noelia);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_fotografia, 'Mirrorless vs DSLR en 2025: ¿tiene sentido comprar una réflex nueva?', '<p>Sony, Fujifilm, Canon y Nikon han migrado completamente a mirrorless. Los sistemas DSLR siguen funcionando excelente pero el desarrollo de nuevas lentes y cuerpos se ha detenido prácticamente. ¿Tiene sentido comprar DSLR nuevo en 2025?</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Tengo una Canon 5D Mark IV desde 2018 y no tengo prisa por migrar. El sistema sigue produciendo imágenes extraordinarias y el costo de migrar todo el parque de lentes es enorme. Si funciona, ¿para qué cambiar?</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El problema es el soporte futuro. Canon ya no desarrolla lentes EF nuevas. En 5-10 años el sistema estará más limitado aún. Migrar ahora o migrar después con equipo más devaluado.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El mercado de segunda mano de lentes EF es enorme y barato precisamente por la migración. Puedes equipar un sistema DSLR profesional por la mitad del precio de mirrorless equivalente ahora mismo.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Para quien está empezando o con presupuesto limitado, DSLR de segunda mano en 2025 sigue siendo probablemente la mejor relación calidad-precio disponible.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El autofoco con detección de sujeto de Sony, Canon R y Nikon Z es genuinamente superior al PDAF de las DSLR. Para fotografía de acción, deportes o wildlife, mirrorless ya ganó el debate definitivamente.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Para retrato y paisaje donde el AF no importa tanto, las diferencias son mucho menores. La imagen final de una 5D con una buena lente sigue siendo indistinguible de una R5 para el 99% de usos.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El sensor estabilizado en cuerpo de los mirrorless modernos es otra ventaja real. Para video y fotografía en condiciones de poca luz, IBIS hace una diferencia sustancial.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La mejor cámara es la que tienes contigo. Un Fujifilm X100VI en el bolsillo captura más fotos que una EOS R3 en casa. La portabilidad tiene un valor enorme que las especificaciones no capturan.</p>', noelia);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_crypto, 'Bitcoin a 100k: ¿activo de reserva legítimo o burbuja perpetua?', '<p>Bitcoin alcanzó los 100,000 dólares y el debate sobre su naturaleza como activo no está más resuelto que hace cinco años. Los bull case y bear case son igualmente articulados y razonables. ¿Dónde está la verdad?</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La adopción institucional con ETFs aprobados en USA fue el cambio de régimen que los bulls esperaban. BlackRock y Fidelity ofreciendo Bitcoin a sus clientes es diferente cualitativamente a ciclos anteriores.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Aunque esa institucionalización también elimina parte del atractivo original. Bitcoin como activo de BlackRock no es exactamente la visión de Satoshi de dinero descentralizado fuera del sistema financiero.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Los dos pueden coexistir. Bitcoin el activo especulativo institucional y Bitcoin la red de pagos descentralizada son capas diferentes del mismo sistema. No tienen que ser mutuamente excluyentes.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>El problema es que los casos de uso reales de la red de pagos son marginales comparados con la especulación. Si el 95% de los usuarios de Bitcoin son especuladores, la narrativa de dinero digital se complica.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El halving de 2024 redujo la emisión a niveles históricamente correlacionados con rallys importantes. El análisis on-chain de los holdings de largo plazo muestra que los holders históricos no están vendiendo. Esas son señales alcistas reales.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El análisis técnico y on-chain ha sido consistentemente optimista en cada ciclo y también ha tenido correcciones del 80%. El pasado no garantiza el futuro en un activo tan joven.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Nadie con credibilidad predice el precio de Bitcoin correctamente de manera consistente. Cualquiera que diga saber a dónde va está mintiendo o vendiendo algo.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Mi posición personal: 5% del portafolio en Bitcoin como seguro contra escenarios extremos de devaluación monetaria. No más porque el riesgo es real, pero cero también es una posición con sus propios riesgos.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Ethereum como plataforma de contratos inteligentes tiene un caso de uso más claro que Bitcoin. El problema es que el ecosistema de competidores como Solana está erosionando su ventaja de red.</p>', noelia);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_espacio, 'SpaceX y la privatización del espacio: ¿progreso o riesgo?', '<p>SpaceX ha reducido el costo de llegar a órbita por un factor de 10 o más comparado con los cohetes de los años 90. Esa reducción de costo está democratizando el acceso al espacio de maneras que eran imposibles hace 20 años. Pero la dependencia de una empresa privada para infraestructura espacial crítica genera preguntas importantes.</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El Falcon 9 con 300+ lanzamientos exitosos consecutivos es el cohete más confiable de la historia. Lo que SpaceX logró en precio y cadencia de lanzamiento era considerado imposible por la industria establecida hace 15 años.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La clave fue la reutilización. Cuando otros decían que recuperar un cohete era imposible, SpaceX lo demostró. Ahora el mismo booster ha volado 20+ veces. El cambio de paradigma económico es real.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Y la competencia que SpaceX creó forzó a ULA, Arianespace y otros a innovar o desaparecer. El mercado competitivo en lanzamientos ha beneficiado a la industria espacial en general.</p>', hannah) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Aunque la dependencia de la NASA en SpaceX para misiones críticas como la ISS es un riesgo de concentración que debería preocupar más a los planificadores de política espacial.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Starship si funciona como prometido cambia todo. Costo por kilo a LEO de miles de dólares a decenas de dólares. Eso hace viable industrialmente el espacio de maneras que hoy son ciencia ficción.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Eso también crea el riesgo de la tragedia de los comunes en órbita baja. Con miles de satélites de Starlink y sus competidores, la contaminación orbital y el síndrome de Kessler son preocupaciones reales.</p>', hannah) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>La regulación internacional del espacio no ha evolucionado al ritmo de la privatización. El Tratado del Espacio Exterior de 1967 no contemplaba esto. Hay un vacío legal que necesita atención urgente.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La misión Artemis y el regreso a la Luna depende en gran parte de SpaceX. Que el destino del programa de exploración humana más ambicioso en décadas esté en manos de una empresa privada tiene implicaciones enormes para la autonomía estratégica de USA.</p>', hannah);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_robotica, 'Robots humanoides en 2025: ¿por qué ahora y no antes?', '<p>Figure, Agility Robotics, Boston Dynamics y Tesla están presentando robots humanoides con capacidades que hace cinco años parecían décadas lejos. La convergencia de hardware asequible, IA de visión y modelos de lenguaje parece haber creado el momento de inflexión que el campo necesitaba.</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La respuesta es los transformers y el aprendizaje por imitación. Por primera vez puedes entrenar un robot mostrándole millones de videos de humanos haciendo tareas. No necesitas programar cada movimiento a mano.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El paper de RT-2 de Google fue el turning point. Combinar visión, lenguaje y acción en un solo modelo que puede generalizarse a tareas no vistas antes era el eslabón perdido de la robótica práctica.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El hardware también maduró. Actuadores eléctricos de alta densidad de potencia, baterías de mayor densidad energética, sensores de fuerza más baratos. Cada componente individual llegó a un umbral de viabilidad al mismo tiempo.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Es la convergencia simultánea de varias curvas de aprendizaje independientes. Cuando muchas tecnologías maduran al mismo tiempo, el producto de sus combinaciones crea saltos no lineales.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El Optimus de Tesla me preocupa menos que el Figure 02 trabajando en almacenes de BMW. Tesla tiene más hype. Figure tiene más clientes reales pagando por trabajo real. Los incentivos económicos aceleran el desarrollo de manera diferente.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>La validación comercial temprana es exactamente lo que le faltó a la robótica en ciclos anteriores. Robots en producción real generan datos reales que aceleran el aprendizaje más que cualquier laboratorio.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El flip side es que el error en un laboratorio es una publicación. El error en una fábrica BMW es un accidente laboral con consecuencias legales reales. La presión para el deployment seguro es enorme.</p>', hannah);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La pregunta más importante no es si los robots humanoides funcionarán sino cómo distribuimos los beneficios cuando lo hagan. La productividad que generan puede ir toda al capital o puede redistribuirse de alguna manera.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Boston Dynamics lleva décadas haciendo robots que impresionan en demos y no escalan comercialmente. El cementerio de demos espectaculares sin producto real es grande. Cautela justificada aunque el momento se vea diferente.</p>', alex);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_medio_amb, 'La energía nuclear como solución climática: por qué los ambientalistas están equivocados en esto', '<p>La oposición ambientalista a la energía nuclear tiene raíces en el movimiento antinuclear de los años 70, una época donde los miedos eran comprensibles. Pero en 2025, con el cambio climático como amenaza existencial, rechazar la fuente de energía de menor carbono disponible a escala parece contraproducente.</p>', hannah) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Alemania cerró sus últimas plantas nucleares y aumentó quema de carbón para compensar. El resultado fue más emisiones, no menos. Ese experimento natural debería haber terminado el debate pero el dogma ambientalista es resistente a los datos.</p>', alex) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Francia con 70% de energía nuclear tiene la electricidad más limpia de Europa Occidental. Y sin el costo de carbono que pagó Alemania en la transición. Los datos son claros.</p>', noelia) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>El problema es el tiempo de construcción y costo. Una planta nuclear tarda 15-20 años en construirse en Occidente y los presupuestos se disparan consistentemente. Para el clima de 2030, no sirve.</p>', hannah) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>Los SMR (Small Modular Reactors) prometen construcción más rápida y modular. Si la promesa se cumple, cambia el argumento del tiempo. Pero todavía están en fase de demostración.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El problema de los residuos nucleares es real aunque manejable. Finlandia está construyendo el primer repositorio permanente del mundo y el volumen total de residuos de alta actividad de toda la historia nuclear cabe en un campo de fútbol.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>El volumen es pequeño pero la vida media es de miles de años. Tomar decisiones que afectan a civilizaciones que no existen todavía tiene una dimensión ética que no se puede ignorar completamente.</p>', hannah) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque las emisiones de carbón también afectan a generaciones futuras por siglos. Comparar los riesgos de los residuos nucleares con los del carbón atmosférico favorece claramente a la nuclear.</p>', alex);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La fusión nuclear como energía siempre está a 30 años de ser realidad. Pero NIF logró ignición en 2022 y las inversiones privadas en startups de fusión son serias ahora. La broma puede estar cerca de dejar de ser una broma.</p>', hannah);
  INSERT INTO topics (channel_id, title, content, author_id) VALUES (ch_emprender, 'El mito del fundador brillante: por qué la narrativa de Steve Jobs destruye startups', '<p>La cultura startup glorifica al visionario solitario que tiene la idea correcta y ejecuta con brillantez contra todos los pronósticos. Esta narrativa es estadísticamente falsa y activamente dañina para la mayoría de los emprendedores que la internalizan.</p>', alex) RETURNING id INTO tid;
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La investigación de Paul Graham y YC es clara: los mejores indicadores de éxito son la comodidad del fundador con la ambigüedad, la velocidad de iteración y la capacidad de escuchar al cliente. El genio solitario no aparece en los datos.</p>', noelia) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Y los co-founders tienen tasas de éxito más altas que los fundadores solos consistentemente. El mito del genio solitario no solo es falso sino que predice peores resultados.</p>', hannah) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Jobs tenía a Wozniak, Gates tenía a Allen, Zuckerberg tenía a Moskovitz. Los mitos de los genios solitarios tienen siempre un co-fundador técnico que se olvida en la narrativa heroica.</p>', alex) RETURNING id INTO r3;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r3, '<p>La narrativa del fundador brillante también crea culturas tóxicas donde el CEO no puede estar equivocado. Theranos es el ejemplo extremo pero el patrón se repite en startups de toda escala.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>El problema mayor es el survivorship bias. Solo escuchamos sobre los Jobs y los Musk que funcionaron. Los miles de fundadores igualmente visionarios que fracasaron no escriben bestsellers ni dan TED talks.</p>', hannah) RETURNING id INTO r1;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r1, '<p>Nassim Taleb lo llama el cementerio silencioso. El riesgo real del emprendimiento no es visible porque los fracasos no se narran. Los libros de emprendimiento son sistemáticamente más optimistas que la realidad.</p>', alex) RETURNING id INTO r2;
  INSERT INTO replies (topic_id, parent_id, content, author_id) VALUES (tid, r2, '<p>Aunque si la narrativa de éxito es lo que impulsa a la gente a intentarlo, quizás un poco de optimismo sesado es funcionalmente necesario para el ecosistema aunque sea epistémicamente cuestionable.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>La mejor formación para emprender no es un MBA ni un libro de Elon Musk sino trabajar en una startup en etapas tempranas. Ver de cerca cómo se resuelven los problemas reales es insustituible.</p>', noelia);
  INSERT INTO replies (topic_id, content, author_id) VALUES (tid, '<p>Customer discovery antes de construir nada. Si hay un pecado capital del startup founder es enamorarse de su solución antes de entender el problema del cliente. Los meses ahorrados de construir lo incorrecto justifican cualquier inversión de tiempo en validación.</p>', alex);
